import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function detectNFTWashTrades(chainName, collectionAddress) {
  const resp = await client.NftService.getNftTransactionsForContractTokenId(
    chainName, collectionAddress, "1"
  );
  const txns = resp.data?.items ?? [];
  // Detect circular trades: wallet sells then re-buys within N blocks
  const addressMap = {};
  txns.forEach(tx => {
    if (!addressMap[tx.from_address]) addressMap[tx.from_address] = [];
    addressMap[tx.from_address].push(tx.to_address);
  });
  const washTrades = Object.entries(addressMap).filter(([from, tos]) =>
    tos.some(to => addressMap[to]?.includes(from))
  );
  return { collectionAddress, washTradeCount: washTrades.length, flaggedAddresses: washTrades.map(([a]) => a) };
}
